import React, { useEffect, useState, useCallback } from 'react';
import { Member } from '../types';
import api from '../utils/api';
import { useLocation } from 'react-router-dom';
import { useAuth } from '../hooks/useAuth';
import Toast from '../components/Toast';

const inp: React.CSSProperties = { width: '100%', padding: '8px 12px', border: '2px solid #e8e0d0', borderRadius: 9, fontSize: 13, fontFamily: 'inherit', outline: 'none', color: '#1a1a2e' };
const TC: any = { student: '#3b82f6', staff: '#8b5cf6' };
const SC: any = { active: '#059669', suspended: '#dc2626', pending: '#d97706' };
const SB: any = { active: '#d1fae5', suspended: '#fee2e2', pending: '#fef3c7' };

export default function Members() {
  const { user } = useAuth();
  const isLibrarian = user?.role === 'librarian';
  const [members, setMembers] = useState<Member[]>([]);
  const [total, setTotal] = useState(0);
  const [page, setPage] = useState(1);
  const [search, setSearch] = useState('');
  const [statusFilter, setStatusFilter] = useState('');
  const [typeFilter, setTypeFilter] = useState('');
  const [loading, setLoading] = useState(true);
  const [modal, setModal] = useState<Member | null>(null);
  const [toast, setToast] = useState<{ message: string; type: 'success'|'error'|'warning'|'info' } | null>(null);
  const location = useLocation();

  const showToast = (message: string, type: 'success'|'error'|'warning'|'info' = 'success') => {
    setToast({ message, type });
  };

  useEffect(() => {
    const params = new URLSearchParams(location.search);
    const s = params.get('status');
    if (s) setStatusFilter(s);
  }, [location.search]);

  const load = useCallback(async () => {
    setLoading(true);
    try {
      const { data } = await api.get('/members', { params: { search, status: statusFilter, type: typeFilter, page, limit: 10 } });
      setMembers(data.data); setTotal(data.total);
    } finally { setLoading(false); }
  }, [search, statusFilter, typeFilter, page]);

  useEffect(() => { load(); }, [load]);

  const updateStatus = async (id: number, status: string, name: string) => {
    try {
      await api.put(`/members/${id}/status`, { status });
      showToast(status === 'active' ? `✓ ${name} approved successfully!` : `${name} status updated to ${status}`, 'success');
      load();
    } catch { showToast('Failed to update status', 'error'); }
  };

  const deleteMember = async (id: number, name: string) => {
    if (!window.confirm(`Delete member "${name}"? This cannot be undone.`)) return;
    try {
      await api.delete(`/members/${id}`);
      showToast(`${name} deleted successfully`, 'success');
      load();
    } catch { showToast('Failed to delete member', 'error'); }
  };

  return (
    <div className="page-enter" style={{ padding: 32 }}>
      {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}

      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 24 }}>
        <div>
          <h1 style={{ fontFamily: "'Playfair Display',serif", fontSize: 28, fontWeight: 700 }}>Members</h1>
          <p style={{ color: '#9ca3af', fontSize: 13, marginTop: 4 }}>{total} registered members</p>
        </div>
      </div>

      {/* Filters */}
      <div style={{ display: 'flex', gap: 12, marginBottom: 20, flexWrap: 'wrap' }}>
        <input style={{ ...inp, flex: 1, minWidth: 200 }} value={search} onChange={e => { setSearch(e.target.value); setPage(1); }} placeholder="🔍  Search name, email, ID..." />
        <select style={{ ...inp, width: 140 }} value={typeFilter} onChange={e => { setTypeFilter(e.target.value); setPage(1); }}>
          <option value="">All Types</option>
          <option value="student">Student</option>
          <option value="staff">Staff</option>
        </select>
        <select style={{ ...inp, width: 150 }} value={statusFilter} onChange={e => { setStatusFilter(e.target.value); setPage(1); }}>
          <option value="">All Status</option>
          <option value="pending">⏳ Pending</option>
          <option value="active">✅ Active</option>
          <option value="suspended">🚫 Suspended</option>
        </select>
      </div>

      {/* Table */}
      <div style={{ background: '#fff', border: '1px solid #e8e0d0', borderRadius: 16, overflow: 'hidden' }}>
        <table style={{ width: '100%', borderCollapse: 'collapse' }}>
          <thead>
            <tr style={{ background: '#f5f0e8' }}>
              {['ID', 'Name', 'Type', 'Department', 'Batch', 'Mobile', 'Status', 'Actions'].map(h => (
                <th key={h} style={{ padding: '11px 16px', textAlign: 'left', fontSize: 11, fontWeight: 700, color: '#6b7280', textTransform: 'uppercase', letterSpacing: '.05em' }}>{h}</th>
              ))}
            </tr>
          </thead>
          <tbody>
            {loading ? (
              <tr><td colSpan={8} style={{ textAlign: 'center', padding: 60, color: '#9ca3af' }}>Loading...</td></tr>
            ) : members.length ? members.map((m, i) => (
              <tr key={m.id} style={{ borderTop: i > 0 ? '1px solid #f5f0e8' : 'none' }}>
                <td style={{ padding: '13px 16px', fontSize: 12, fontFamily: 'monospace', fontWeight: 700, color: '#c9a84c' }}>{m.member_id}</td>
                <td style={{ padding: '13px 16px' }}>
                  <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
                    <div style={{ width: 32, height: 32, background: '#1a1a2e', borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center', fontWeight: 700, color: '#c9a84c', fontSize: 12, flexShrink: 0 }}>{m.name.charAt(0)}</div>
                    <div>
                      <div style={{ fontSize: 13, fontWeight: 600 }}>{m.name}</div>
                      <div style={{ fontSize: 11, color: '#9ca3af' }}>{m.email.toLowerCase()}</div>
                    </div>
                  </div>
                </td>
                <td style={{ padding: '13px 16px' }}>
                  <span style={{ fontSize: 11, fontWeight: 600, padding: '3px 10px', borderRadius: 99, background: (TC[m.account_type] || '#6b7280') + '20', color: TC[m.account_type] || '#6b7280', textTransform: 'capitalize' }}>
                    {m.account_type === 'student' ? '🎓' : '👨‍💼'} {m.account_type}
                  </span>
                </td>
                <td style={{ padding: '13px 16px', fontSize: 13, color: '#6b7280' }}>{m.department || '—'}</td>
                <td style={{ padding: '13px 16px', fontSize: 13, color: '#6b7280' }}>{m.batch || '—'}</td>
                <td style={{ padding: '13px 16px', fontSize: 13, color: '#6b7280' }}>{m.mobile || '—'}</td>
                <td style={{ padding: '13px 16px' }}>
                  <span style={{ fontSize: 11, fontWeight: 600, padding: '3px 10px', borderRadius: 99, background: SB[m.status] || '#f3f4f6', color: SC[m.status] || '#6b7280', textTransform: 'capitalize' }}>
                    {m.status}
                  </span>
                </td>
                <td style={{ padding: '13px 16px' }}>
                  <div style={{ display: 'flex', gap: 4, flexWrap: 'wrap' }}>
                    {m.status === 'pending' && (
                      <button onClick={() => updateStatus(m.id, 'active', m.name)}
                        style={{ padding: '5px 10px', background: '#d1fae5', color: '#059669', border: 'none', borderRadius: 7, fontSize: 11, cursor: 'pointer', fontWeight: 600 }}>
                        ✓ Approve
                      </button>
                    )}
                    {m.status === 'active' && (
                      <button onClick={() => updateStatus(m.id, 'suspended', m.name)}
                        style={{ padding: '5px 10px', background: '#fee2e2', color: '#dc2626', border: 'none', borderRadius: 7, fontSize: 11, cursor: 'pointer' }}>
                        Suspend
                      </button>
                    )}
                    {m.status === 'suspended' && (
                      <button onClick={() => updateStatus(m.id, 'active', m.name)}
                        style={{ padding: '5px 10px', background: '#d1fae5', color: '#059669', border: 'none', borderRadius: 7, fontSize: 11, cursor: 'pointer' }}>
                        Activate
                      </button>
                    )}
                    <button onClick={() => setModal(m)}
                      style={{ padding: '5px 10px', background: '#f5f0e8', border: 'none', borderRadius: 7, fontSize: 11, cursor: 'pointer' }}>
                      View
                    </button>
                    {/* শুধু Librarian delete করতে পারবে */}
                    {isLibrarian && (
                      <button onClick={() => deleteMember(m.id, m.name)}
                        style={{ padding: '5px 10px', background: '#fee2e2', color: '#dc2626', border: 'none', borderRadius: 7, fontSize: 11, cursor: 'pointer' }}>
                        Delete
                      </button>
                    )}
                  </div>
                </td>
              </tr>
            )) : <tr><td colSpan={8} style={{ textAlign: 'center', padding: 60, color: '#9ca3af' }}>👤 No members found</td></tr>}
          </tbody>
        </table>
      </div>

      {/* Pagination */}
      {Math.ceil(total / 10) > 1 && (
        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 8, marginTop: 20 }}>
          <button onClick={() => setPage(p => Math.max(1, p - 1))} disabled={page === 1} style={{ padding: '7px 16px', background: '#e8e0d0', border: 'none', borderRadius: 8, cursor: 'pointer', opacity: page === 1 ? 0.4 : 1 }}>← Prev</button>
          <span style={{ fontSize: 13, color: '#6b7280' }}>Page {page} of {Math.ceil(total / 10)}</span>
          <button onClick={() => setPage(p => Math.min(Math.ceil(total / 10), p + 1))} disabled={page === Math.ceil(total / 10)} style={{ padding: '7px 16px', background: '#e8e0d0', border: 'none', borderRadius: 8, cursor: 'pointer', opacity: page === Math.ceil(total / 10) ? 0.4 : 1 }}>Next →</button>
        </div>
      )}

      {/* View Modal */}
      {modal && (
        <div style={{ position: 'fixed', inset: 0, background: 'rgba(26,26,46,0.5)', backdropFilter: 'blur(4px)', zIndex: 1000, display: 'flex', alignItems: 'center', justifyContent: 'center', padding: 20 }}>
          <div style={{ background: '#fff', borderRadius: 20, padding: 28, width: '100%', maxWidth: 460 }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 20 }}>
              <h2 style={{ fontFamily: "'Playfair Display',serif", fontSize: 20, fontWeight: 700 }}>Member Details</h2>
              <button onClick={() => setModal(null)} style={{ background: '#f5f0e8', border: 'none', width: 32, height: 32, borderRadius: 8, cursor: 'pointer', fontSize: 16 }}>✕</button>
            </div>
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 12 }}>
              {[
                ['Member ID', modal.member_id],
                ['Account Type', modal.account_type],
                ['Full Name', modal.name],
                ['Email', modal.email.toLowerCase()],
                ['Department', modal.department || '—'],
                ['Batch', modal.batch || '—'],
                ['Mobile', modal.mobile || '—'],
                ['Gender', modal.gender || '—'],
                ['Status', modal.status],
              ].map(([label, value]) => (
                <div key={label} style={{ background: '#f5f0e8', borderRadius: 10, padding: 12 }}>
                  <div style={{ fontSize: 11, fontWeight: 600, color: '#9ca3af', marginBottom: 4, textTransform: 'uppercase' }}>{label}</div>
                  <div style={{ fontSize: 13, fontWeight: 600, color: '#1a1a2e', textTransform: label === 'Email' ? 'none' : 'capitalize' }}>{value}</div>
                </div>
              ))}
              {modal.address && (
                <div style={{ gridColumn: '1/-1', background: '#f5f0e8', borderRadius: 10, padding: 12 }}>
                  <div style={{ fontSize: 11, fontWeight: 600, color: '#9ca3af', marginBottom: 4, textTransform: 'uppercase' }}>Address</div>
                  <div style={{ fontSize: 13, color: '#1a1a2e' }}>{modal.address}</div>
                </div>
              )}
            </div>
            {modal.status === 'pending' && (
              <button onClick={() => { updateStatus(modal.id, 'active', modal.name); setModal(null); }}
                style={{ width: '100%', marginTop: 16, padding: 12, background: '#059669', color: '#fff', border: 'none', borderRadius: 10, fontSize: 14, fontWeight: 600, cursor: 'pointer', fontFamily: 'inherit' }}>
                ✓ Approve This Member
              </button>
            )}
          </div>
        </div>
      )}
    </div>
  );
}
